select
  s.id, 'board', NULL, 'Resident ถามเรื่อง evidence-based medicine + clinical decision-making', '[{"label":"A","text":"Random"},{"label":"B","text":"Evidence-Based Medicine Framework: (1) **Hierarchy of evidence** (lowest to highest): expert opinion < case series < cohort < RCT < systematic review/meta-analysis < GRADE-rated guidelines; (2) **5A approach**: Ask (clinical question) + Acquire (search literature) + Appraise (validity, importance) + Apply (to patient) + Assess (outcomes); (3) **PICO framework** clinical question: Patient/Problem + Intervention + Comparison + Outcome; (4) **Study design**: RCT for treatment efficacy; cohort for prognosis; case-control for rare conditions; cross-sectional for prevalence; diagnostic accuracy studies; (5) **Critical appraisal**: validity (internal, external), bias, statistical analysis, clinical significance; (6) **Statistical concepts**: p-value, confidence interval, RR, OR, HR, NNT/NNH, sensitivity, specificity, PPV/NPV, LR, kappa, ICC; (7) **Bayesian reasoning**: pre-test + post-test probability + likelihood ratios; (8) **Clinical decision-making**: integrate evidence + clinical expertise + patient values; shared decision-making; (9) **Guidelines**: GRADE methodology — strong vs conditional recommendations; (10) **EBM application** in primary care: more applicable to common conditions, individualize, use clinical decision tools (Wells, HEART, FRAX), point-of-care tools (UpToDate, DynaMed, BMJ Best Practice); (11) **EBM critiques**: limitations (RCT external validity, dominant pharmaceutical influence, individual application)"},{"label":"C","text":"Single study basis"},{"label":"D","text":"Expert opinion only"},{"label":"E","text":"Random"}]'::jsonb,
  'B', 'EBM: hierarchy + 5A + PICO + critical appraisal + Bayesian. GRADE methodology. Integrate evidence + expertise + patient values. Primary care: clinical decision tools + shared decision-making. Modern: precision + value-based + individualized.', NULL,
  'medium', 'signs_symptoms', 'review',
  'family_medicine', 'basic_science', 'signs_symptoms', 'adult',
  'AAFP EBM; Sackett EBM', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'fammed_basic_science'
  and s.audience = 'board'
