select
  s.id, 'board', NULL, 'Resident ถามเรื่อง pharmacology — common medications + interactions in primary care', '[{"label":"A","text":"Random"},{"label":"B","text":"Primary Care Pharmacology + Drug Interactions: (1) **Common drug-drug interactions**: warfarin + many (NSAIDs, antibiotics — INR fluctuations); SSRIs + tramadol (serotonin syndrome); statins + macrolides/azoles (rhabdo); ACEi + K-sparing diuretic (hyperkalemia); levothyroxine + Ca/iron/PPI (reduce absorption); colchicine + clarithromycin (toxicity); (2) **Pharmacokinetics**: absorption (food, gastric pH, formulation), distribution (Vd, protein binding), metabolism (CYP450 — 3A4, 2D6, 2C19 polymorphisms), excretion (renal, hepatic); (3) **Renal dose adjustment**: many medications require eGFR-based adjustment; (4) **Hepatic considerations**: statins, acetaminophen ceiling, opioids; (5) **Beers Criteria** for elderly — PIMs (potentially inappropriate medications): benzodiazepines, anticholinergic, NSAIDs, certain CV meds; (6) **STOPP/START** complementary deprescribing; (7) **Pregnancy + lactation**: FDA categories replaced by PLLR; LactMed for breastfeeding; (8) **Pediatric**: weight-based; specific avoidances (ceftriaxone < 4 wk, codeine < 12 yr, tetracycline < 8 yr, aspirin viral); (9) **Generic vs brand**: most generics bioequivalent; selected exceptions; cost; (10) **Resources**: Epocrates, Lexicomp, Micromedex, PharmGKB; CDC adult immunization; (11) **Polypharmacy management**: regular review, simplify, deprescribe; (12) **Medication adherence**: barriers + interventions (synchronization, blister packs, family involvement, education); (13) **Cost**: generic, formulary, assistance programs"},{"label":"C","text":"No interactions"},{"label":"D","text":"Random"},{"label":"E","text":"Ignore"}]'::jsonb,
  'B', 'Primary care pharmacology: common interactions + PK + renal/hepatic adjustment + Beers + pregnancy + pediatric considerations. Polypharmacy management. Adherence + cost. Resources for decision support. Modern: precision medicine + safety + value.', NULL,
  'medium', 'procedures', 'review',
  'family_medicine', 'basic_science', 'procedures', 'adult',
  'AAFP; Beers Criteria', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
