select
  s.id, 'board', NULL, 'หญิงอายุ 32 ปี G3P2 GA 28 wk ANC ตรวจพบ GDM screening positive (OGTT fasting 105, 1h 195, 2h 168 — meets ADA/ACOG criteria)

ก่อนหน้านี้ลูก 1 คนเป็น macrosomia 4.2kg shoulder dystocia
Family history: father DM type 2', '[{"label":"A","text":"Ignore — manage after delivery"},{"label":"B","text":"Gestational Diabetes Mellitus (GDM) management: (1) Medical nutrition therapy first-line (registered dietitian — 40-50% calories from carb, 20% protein, 30-40% fat, distributed 3 meals + 2-3 snacks); (2) Exercise 30 min/d if no contraindication; (3) Self-monitor blood glucose 4×/d (fasting + 1 or 2h postprandial) — targets: fasting < 95, 1h < 140, 2h < 120; (4) Pharmacotherapy if MNT fail (target not met 50% of time after 1-2 wk): **insulin** preferred (does not cross placenta — long-acting NPH/detemir/glargine + rapid lispro/aspart); metformin/glyburide alternatives (cross placenta, ACOG accepts but insulin preferred); (5) Antepartum surveillance — NST + AFI weekly from 32-34 wk; (6) Delivery timing — 39-40 wk uncomplicated GDM on diet; 39 wk if on medication well-controlled; earlier if complications; (7) Intrapartum: glucose control 70-110, insulin drip if needed; (8) Postpartum: usually return to normal; OGTT 6-12 wk postpartum (50% develop T2DM lifetime); (9) Lifestyle: weight, exercise, prevention; (10) Recurrence high in future pregnancies"},{"label":"C","text":"Insulin without diet education"},{"label":"D","text":"Cesarean immediately"},{"label":"E","text":"Restrict carbohydrate completely"}]'::jsonb,
  'B', 'GDM: glucose intolerance first recognized in pregnancy. Screening 24-28 wk (1-step OGTT 75g or 2-step). Management: MNT first, insulin if MNT fail (insulin preferred — no placental crossing). Surveillance + delivery timing. Macrosomia, shoulder dystocia, preeclampsia, NICU risks. Postpartum OGTT — 50% develop T2DM. Lifestyle modification reduces.', NULL,
  'easy', 'obgyn', 'review',
  'ob_gyn', 'clinical_decision', 'obgyn', 'adult',
  'ACOG Practice Bulletin: Gestational Diabetes Mellitus 2018; ADA Standards of Care 2024', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'obg_clinical_decision'
