select
  s.id, 'board', NULL, 'หญิงอายุ 65 ปี recently diagnosed advanced ovarian cancer (Stage IIIC) on chemotherapy — counsel + integrative care across cancer survivorship', '[{"label":"A","text":"Chemotherapy alone"},{"label":"B","text":"Gynecologic Cancer Survivorship Integrative Care: (1) Active treatment: oncology team coordinated care, side effect management (nausea/vomiting, neuropathy, fatigue, alopecia, infection prevention, growth factors), nutritional support, exercise programs (improves outcomes), psychological + spiritual support; (2) Long-term survivorship (modern: many survive significantly with better Rx): - surveillance (clinical, CA-125, imaging) for recurrence; - PARP inhibitor maintenance if BRCA+; - secondary cancer screening; - cardiovascular monitoring (cardiotoxicity from some chemo); - bone health (DEXA, calcium, vitamin D); - sexual health (vaginal estrogen for GSM safe in non-hormone responsive cancers, lubricants, sexual therapy); - reproductive (premature ovarian failure if young — hormone considerations); - emotional/psychological (PTSD, anxiety, depression — high prevalence); - financial toxicity counseling; - return to work/role; (3) Survivorship care plan — written summary + plan provided; (4) Multidisciplinary: oncology, primary care, social work, psychology, nutrition, physical therapy, sexual health; (5) Family/caregiver support + bereavement preparation; (6) Palliative care integration (early palliative + curative treatment — Temel; recurrent disease — symptom + QOL focus); (7) End-of-life if appropriate — advance care planning, hospice; (8) Patient advocacy + support groups; (9) Genetic counseling — family screening for inherited cancer; (10) Equity in care + cultural competence"},{"label":"C","text":"Stop all treatment"},{"label":"D","text":"Avoid follow-up"},{"label":"E","text":"Hospice only"}]'::jsonb,
  'B', 'Cancer survivorship integrative care = multidisciplinary + lifelong. Modern ovarian cancer outcomes improving (PARP inhibitors). Survivorship care plan (IOM 2006). Multiple domains: surveillance, late effects, sexual health, mental health, return to function, financial, family. Integrated palliative care from diagnosis (Temel — improves QOL + survival). Family + caregiver support. Genetic counseling — implications for family. Continuous quality of life focus.', NULL,
  'hard', 'hemato_onco', 'review',
  'ob_gyn', 'integrative', 'hemato_onco', 'adult',
  'ASCO Cancer Survivorship Care Planning; IOM From Cancer Patient to Cancer Survivor 2006; NCCN Survivorship Guidelines', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'obg_integrative'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
