select
  s.id, 'board', NULL, 'ชายไทยอายุ 25 ปี ขับมอเตอร์ไซค์ชน ถูกรถยนต์ชนเข้ามาห้องฉุกเฉิน ปวดต้นขาขวาอย่างรุนแรง

V/S: BP 96/64, HR 122, RR 22, SpO2 96%
PE: right thigh swollen, tender, deformed, shortened
Palpable distal pulses, no open wound, no neurological deficit
Length discrepancy 4 cm

X-ray: closed midshaft femoral fracture, displaced, comminuted', '[{"label":"A","text":"Cast immobilization"},{"label":"B","text":"Closed Femoral Shaft Fracture in young adult: (1) Initial: ATLS protocol, IV access × 2, fluid resuscitation (femoral fracture loses 1-1.5 L blood), pain control, traction splint (Hare/Sager) for transport + pain; (2) Definitive: **antegrade reamed intramedullary nailing (IMN)** within 24-48 hours — standard of care for closed femoral shaft (early stabilization reduces ARDS, fat embolism, length of stay); (3) Damage control orthopedics — external fixation if polytrauma + hemodynamic instability + delayed definitive within days; (4) Antibiotic prophylaxis (cefazolin pre-op); (5) Compartment syndrome screening (rare in thigh but possible); (6) Tetanus update if needed; (7) VTE prophylaxis (mechanical immediate + chemical when bleeding controlled); (8) Post-op: early mobilization with weight bearing as tolerated typically with locked IMN, PT, follow-up X-rays for healing; (9) Complications: malunion, nonunion, infection, knee stiffness, AVN (rare); (10) Return to function 4-6 months for athletic activity"},{"label":"C","text":"Conservative + bedrest"},{"label":"D","text":"Amputation"},{"label":"E","text":"Manipulation in ED"}]'::jsonb,
  'B', 'Femoral shaft fracture in young adult: IMN is gold standard (closed, locked, reamed). Early stabilization < 24-48h reduces pulmonary complications (ARDS, fat embolism). Damage control orthopedics for polytrauma. Blood loss substantial. Multidisciplinary trauma care. Modern IMN: > 95% union, early weight-bearing, return to function 4-6 months.', NULL,
  'easy', 'trauma', 'review',
  'orthopedics', 'clinical_decision', 'trauma', 'adult',
  'AAOS; OTA (Orthopedic Trauma Association) Guidelines', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'ortho_clinical_decision'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'orthopedics'
      and q.scenario = 'ชายไทยอายุ 25 ปี ขับมอเตอร์ไซค์ชน ถูกรถยนต์ชนเข้ามาห้องฉุกเฉิน ปวดต้นขาขวาอย่างรุนแรง

V/S: BP 96/64, HR 122, RR 22, SpO2 96%
PE: right thigh swollen, tender, deformed, shortened
Palpable distal pulses, no open wound, no neurological deficit
Length discrepancy 4 cm

X-ray: closed midshaft femoral fracture, displaced, comminuted'
  );

