select
  s.id, 'board', NULL, 'ชายไทยอายุ 22 ปี soccer player เปลี่ยนทิศทางขณะวิ่ง รู้สึก pop ในเข่า ขวา + ปวด + บวมทันที + ไม่สามารถเดินได้

MRI knee: complete tear of ACL + partial tear MCL + medial meniscus tear', '[{"label":"A","text":"Bedrest"},{"label":"B","text":"ACL Tear + Multi-ligament Injury (young active athlete): (1) Initial: RICE (rest, ice, compression, elevation), pain control, knee immobilizer or hinged brace; PT pre-operatively (\"prehab\") improves outcomes; (2) **ACL reconstruction** indications: young, active, return to sports + cutting/pivoting activities + instability; technique: arthroscopic ACL reconstruction with autograft (bone-patellar tendon-bone, hamstring tendon, quadriceps tendon) or allograft; concurrent meniscal repair (preserve when possible) or partial meniscectomy; MCL grade I-II often heal with bracing (delayed ACL); grade III MCL with concurrent ACL — may consider acute repair vs staged; (3) **Non-operative** acceptable for sedentary, low demand, partial tears, willing to modify activity (\"copers\"); (4) **Timing**: delay 2-4 weeks until swelling resolved, ROM regained — reduces arthrofibrosis risk (Shelbourne accelerated rehab); some advocate earlier; (5) **Post-op**: prolonged rehab 6-9 months for return to sport; ACL-RSI score for psychological readiness; (6) **Outcomes**: 85-90% return to sport, 65% to pre-injury level; (7) Long-term: increased OA risk (50% at 10-15 yr), prevention strategies (neuromuscular training programs — FIFA 11+); (8) Multidisciplinary: sports medicine, PT, athletic trainer, psychologist; (9) Female athletes higher ACL injury risk (anatomy, hormonal, biomechanics) — prevention programs especially important"},{"label":"C","text":"Cast 6 months"},{"label":"D","text":"Total knee replacement"},{"label":"E","text":"Amputation"}]'::jsonb,
  'B', 'ACL tear: common sports injury (pivoting, cutting). MOI: non-contact deceleration with rotation. Diagnosis: clinical (Lachman, pivot shift) + MRI. Treatment: surgical reconstruction for young active; non-operative for selected. Concurrent injuries common ("unhappy triad" — ACL + MCL + medial meniscus). Long rehab (6-9 mo) to return to sport. Long-term OA risk despite surgery. Female athletes higher risk. Prevention programs (neuromuscular training).', NULL,
  'medium', 'trauma', 'review',
  'orthopedics', 'clinical_decision', 'trauma', 'adult',
  'AAOS Clinical Practice Guideline: Management of Anterior Cruciate Ligament Injuries 2014, updated 2022', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'ortho_clinical_decision'
  and s.audience = 'board'
  and not exists (
