select
  s.id, 'board', NULL, 'หญิงไทยอายุ 42 ปี post-laparoscopic cholecystectomy day 5 มาห้องฉุกเฉินด้วยอาการ ไข้, ปวด RUQ, jaundice, bilirubin 6.2 ตรวจ MRCP พบ bile duct injury (Strasberg E2 — common bile duct transection > 2 cm from confluence) + bile collection 6 cm in subhepatic space

V/S: BP 122/74, HR 96, RR 18, Temp 38.4°C, WBC 14,500', '[{"label":"A","text":"Repeat laparoscopy + simple suture repair"},{"label":"B","text":"Major Bile Duct Injury (Strasberg E2) post-cholecystectomy — multidisciplinary referral to HPB center: (1) **Control sepsis** — IV antibiotics + percutaneous drainage of biloma + ERCP with stent or PTBD for biliary diversion; (2) **Delayed definitive reconstruction** 6-8 weeks later (allow inflammation to resolve) — **Roux-en-Y hepaticojejunostomy** is gold standard; (3) Avoid attempts at primary repair in non-HPB centers (high stricture/leak rate); (4) Long-term complications: stricture (10-30%), recurrent cholangitis, secondary biliary cirrhosis; (5) Medico-legal documentation"},{"label":"C","text":"Conservative observation only"},{"label":"D","text":"Total hepatectomy + transplant"},{"label":"E","text":"Discharge with oral antibiotic"}]'::jsonb,
  'B', 'Bile duct injury (BDI) — feared complication of cholecystectomy (0.3-0.6%). Strasberg classification A-E (E1-E5 = main duct injuries). Management principles: control sepsis (drainage + antibiotic), divert bile (ERCP/PTBD), refer to HPB specialist, delayed Roux-en-Y hepaticojejunostomy at 6-8 weeks for major injuries. Primary repair attempts by non-specialists have high failure rate (stricture, recurrent cholangitis, secondary cirrhosis). Outcome depends on time to specialist referral and surgeon expertise. A wrong — simple suture fails. C wrong — biloma + sepsis can''t observe. D wrong — transplant for end-stage liver only. E wrong — outpatient unsafe.', NULL,
  'hard', 'gi', 'review',
  'surgery', 'clinical_decision', 'gi', 'adult',
  'Strasberg SM et al. J Am Coll Surg 1995 (Classification); ATOM/Sicklick Ann Surg 2005 (BDI management); SAGES Safe Cholecystectomy Program', 'AI-generated-board-seed', true, 'seeded via Claude Code session (no critique pass)'
from public.mcq_subjects s
where s.name = 'surg_clinical_decision'
  and s.audience = 'board'
  and not exists (
    select 1 from public.mcq_questions q
    where q.exam_source = 'AI-generated-board-seed'
      and q.board_specialty = 'surgery'
      and q.scenario = 'หญิงไทยอายุ 42 ปี post-laparoscopic cholecystectomy day 5 มาห้องฉุกเฉินด้วยอาการ ไข้, ปวด RUQ, jaundice, bilirubin 6.2 ตรวจ MRCP พบ bile duct injury (Strasberg E2 — common bile duct transection > 2 cm from confluence) + bile collection 6 cm in subhepatic space

V/S: BP 122/74, HR 96, RR 18, Temp 38.4°C, WBC 14,500'
  );

